import pyotp
from qrcode import QRcode
import datetime

class TOTPAuth:
    def __init__(self, secret):
        self.totp = pyotp.TOTP(secret)

    def generate_qr_code(self, user_name):
        qr = pyotp.libqrencode.QRCode()
        qr.add_data(f"otpauth://totp/{user_name}?secret={self.totp.key}&issuer=YourCompany")
        qr.make_image()

    def validate_totp_code(self, code):
        return self.totp.verify(code)

def generate_secret():
    return pyotp.random_base32()

